from replay_copy import mirror_window


def test_source_rows_are_copied_to_empty_sink():
    source = {"XYZ": [{"bid": 10.0}, {"bid": 10.1}]}
    sink = {}
    assert mirror_window(source, sink, "XYZ") == 2
    assert sink["XYZ"] == source["XYZ"]
    assert sink["XYZ"] is not source["XYZ"]


def test_existing_sink_is_replaced_by_source_window():
    source = {"XYZ": [{"bid": 11.0}]}
    sink = {"XYZ": [{"bid": 1.0}]}
    assert mirror_window(source, sink, "XYZ") == 1
    assert sink["XYZ"] == [{"bid": 11.0}]
